// frontend/src/pages/Applications.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import '../App.css';

const Applications = () => {
    const [apps, setApps] = useState([]);
    const [showForm, setShowForm] = useState(false);
    const [form, setForm] = useState({ company: '', position: '', status: 'applied' });
    const [loading, setLoading] = useState(true);
    const [message, setMessage] = useState('');
    const [isAuthenticated, setIsAuthenticated] = useState(true);

    const token = localStorage.getItem('token');
    const API_URL = 'http://localhost:5000';

    useEffect(() => {
        if (!token) {
            setIsAuthenticated(false);
            setLoading(false);
            return;
        }
        fetchApps();
    }, []);

    const fetchApps = async () => {
        try {
            const res = await axios.get(`${API_URL}/api/applications`, {
                headers: { 'x-auth-token': token }
            });
            setApps(res.data);
        } catch (error) {
            console.error('Error fetching applications:', error);
            if (error.response?.status === 401) {
                setIsAuthenticated(false);
            }
        }
        setLoading(false);
    };

    const addApp = async (e) => {
        e.preventDefault();
        
        if (!form.company || !form.position) {
            setMessage('Please fill company and position');
            setTimeout(() => setMessage(''), 3000);
            return;
        }

        // Try different possible field formats
        const applicationData = {
            // Format 1
            company: form.company,
            position: form.position,
            status: form.status,
            // Format 2 (alternative)
            companyName: form.company,
            jobTitle: form.position,
            // Format 3 (with date)
            date: new Date().toISOString()
        };

        console.log('Sending data:', applicationData);

        try {
            const res = await axios.post(
                `${API_URL}/api/applications`,
                applicationData,
                { headers: { 'x-auth-token': token } }
            );
            
            console.log('Response:', res.data);
            
            setMessage('✅ Application added successfully!');
            setTimeout(() => setMessage(''), 3000);
            setShowForm(false);
            setForm({ company: '', position: '', status: 'applied' });
            fetchApps();
        } catch (error) {
            console.error('Error details:', error.response?.data);
            
            // Show detailed error
            if (error.response?.data) {
                setMessage(`❌ Error: ${JSON.stringify(error.response.data)}`);
            } else {
                setMessage('❌ Error adding application. Check console for details.');
            }
            setTimeout(() => setMessage(''), 5000);
        }
    };

    const deleteApp = async (id) => {
        if (window.confirm('Delete this application?')) {
            try {
                await axios.delete(`${API_URL}/api/applications/${id}`, {
                    headers: { 'x-auth-token': token }
                });
                fetchApps();
                setMessage('✅ Application deleted');
                setTimeout(() => setMessage(''), 2000);
            } catch (error) {
                console.error('Error deleting application:', error);
                setMessage('❌ Error deleting application');
                setTimeout(() => setMessage(''), 3000);
            }
        }
    };

    if (!isAuthenticated) {
        return (
            <div className="container text-center" style={{ padding: '50px' }}>
                <div className="card">
                    <h2>🔒 Please Login First</h2>
                    <button onClick={() => window.location.href = '/login'}>
                        Go to Login
                    </button>
                </div>
            </div>
        );
    }

    if (loading) {
        return <div className="text-center" style={{ padding: '50px' }}>Loading...</div>;
    }

    return (
        <div className="container">
            <div className="flex-between" style={{ marginBottom: '20px' }}>
                <h1>📝 Applications</h1>
                <button onClick={() => setShowForm(!showForm)}>
                    {showForm ? '✖ Cancel' : '+ Add Application'}
                </button>
            </div>

            {message && (
                <div className={message.includes('✅') ? 'success' : 'error'}>
                    {message}
                </div>
            )}

            {showForm && (
                <div className="card">
                    <h3>➕ New Application</h3>
                    <form onSubmit={addApp}>
                        <input
                            type="text"
                            placeholder="Company Name *"
                            value={form.company}
                            onChange={(e) => setForm({ ...form, company: e.target.value })}
                            required
                        />
                        <input
                            type="text"
                            placeholder="Job Position *"
                            value={form.position}
                            onChange={(e) => setForm({ ...form, position: e.target.value })}
                            required
                        />
                        <select
                            value={form.status}
                            onChange={(e) => setForm({ ...form, status: e.target.value })}
                        >
                            <option value="applied">📧 Applied</option>
                            <option value="interview">🎯 Interview</option>
                            <option value="offered">🎉 Offered</option>
                            <option value="rejected">❌ Rejected</option>
                        </select>
                        <button type="submit">💾 Save Application</button>
                    </form>
                </div>
            )}

            <div className="card">
                {apps.length === 0 ? (
                    <div className="text-center" style={{ padding: '40px' }}>
                        <p>📭 No applications yet</p>
                        <button onClick={() => setShowForm(true)}>+ Add Your First Application</button>
                    </div>
                ) : (
                    <div style={{ overflowX: 'auto' }}>
                        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                            <thead>
                                <tr>
                                    <th style={{ textAlign: 'left', padding: '12px', borderBottom: '1px solid #eee' }}>Company</th>
                                    <th style={{ textAlign: 'left', padding: '12px', borderBottom: '1px solid #eee' }}>Position</th>
                                    <th style={{ textAlign: 'left', padding: '12px', borderBottom: '1px solid #eee' }}>Status</th>
                                    <th style={{ textAlign: 'left', padding: '12px', borderBottom: '1px solid #eee' }}>Date</th>
                                    <th style={{ textAlign: 'left', padding: '12px', borderBottom: '1px solid #eee' }}>Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {apps.map(app => (
                                    <tr key={app._id}>
                                        <td style={{ padding: '12px', borderBottom: '1px solid #eee' }}><strong>{app.company || app.companyName}</strong></td>
                                        <td style={{ padding: '12px', borderBottom: '1px solid #eee' }}>{app.position || app.jobTitle}</td>
                                        <td style={{ padding: '12px', borderBottom: '1px solid #eee' }}>
                                            <span className={`status status-${app.status || 'applied'}`}>
                                                {app.status || 'applied'}
                                            </span>
                                        </td>
                                        <td style={{ padding: '12px', borderBottom: '1px solid #eee' }}>{new Date(app.date || app.createdAt).toLocaleDateString()}</td>
                                        <td style={{ padding: '12px', borderBottom: '1px solid #eee' }}>
                                            <button 
                                                onClick={() => deleteApp(app._id)} 
                                                style={{ background: '#e74c3c', padding: '5px 10px' }}
                                            >
                                                🗑️ Delete
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>
        </div>
    );
};

export default Applications;
